class Solution {public: int minCoins(int n, vector<int>& coins, int amount){ int memo[n+1][amount+1]={0};
for(int i=0;i<=n;i++){
    for(int j=0;j<=amount;j++){
        if(i==0){ memo[i][j]=0; }
        else if(j==0){ memo[i][j]=0; }
        else if(memo[i-1][j]!=0){ memo[i][j]=memo[i-1][j]; }
        else{ memo[i][j]=1+memo[i][j-coins[i-1]]; }
    }
}
return memo[n][amount];
}

